### Combine ListEventTypes with EventTypeSettings

Source: https://github.com/calcom/cal.com/blob/main/docs/platform/atoms/list-event-types.mdx

This example demonstrates combining the ListEventTypes atom with EventTypeSettings for a complete event type management interface. It includes setting up a dynamic route to handle event type IDs and passing them to EventTypeSettings. The onSuccess callback is triggered upon successful updates.

```tsx
import { useRouter } from "next/router";

import { CalProvider, EventTypeSettings } from "@calcom/atoms";

export default function EventTypeSettingsPage() {
  const router = useRouter();
  const eventTypeId = Number(router.query.eventTypeId);

  if (!eventTypeId) return null;

  return (
    <CalProvider clientId="your-client-id" accessToken="user-access-token">
      <EventTypeSettings
        id={eventTypeId}
        onSuccess={() => {
          console.log("Event type updated successfully");
        }}
      />
    </CalProvider>
  );
}
```

